import{_ as a,c as e,o as m,b as t}from"./app.5ff54e83.js";const c=JSON.parse('{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 6","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 6","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 1.","toc":true,"tags":"vim-1","sans":"\u0936\u0915\u094D\u0924\u093F\u091A\u0915\u094D\u0930\u0938\u0928\u094D\u0927\u093E\u0928\u0947 \u0935\u093F\u0936\u094D\u0935\u0938\u0902\u0939\u093E\u0930\u0903","trans":"\u015Aakticakrasandh\u0101ne vi\u015Bvasa\u1E41h\u0101ra\u1E25","date":"2021-02-19T00:00:00.000Z"},"headers":[{"level":3,"title":"\u015Aakticakrasandh\u0101ne vi\u015Bvasa\u1E41h\u0101ra\u1E25||6||","slug":"sakticakrasandhane-visvasamharah-6"}],"relativePath":"texts/shiva-sutra-vimarshini/1/6/index.md"}'),i={name:"texts/shiva-sutra-vimarshini/1/6/index.md"},r=t('<div class="stanza"><a href="#s1.6" id="s1.6" class="num">1.6</a><div class="sans"><p>\u090F\u0935\u0902 \u091D\u0917\u093F\u0924\u093F \u092A\u0930\u092A\u094D\u0930\u0924\u093F\u092D\u094B\u0928\u094D\u092E\u0947\u0937\u093E\u0935\u0937\u094D\u091F\u092E\u094D\u092D\u094B\u092A\u093E\u092F\u093F\u0915\u093E\u0902 \u092D\u0948\u0930\u0935\u0938\u092E\u093E\u092A\u0924\u094D\u0924\u093F\u092E\u091C\u094D\u091E\u093E\u0928\u092C\u0928\u094D\u0927\u092A\u094D\u0930\u0936\u092E\u0948\u0915\u0939\u0947\u0924\u0941\u0902 \u092A\u094D\u0930\u0926\u0930\u094D\u0936\u094D\u092F\u0948\u0924\u0924\u094D\u092A\u0930\u093E\u092E\u0930\u094D\u0936\u092A\u094D\u0930\u0915\u0930\u094D\u0937\u093E\u0926\u094D\u0935\u094D\u092F\u0941\u0924\u094D\u0925\u093E\u0928\u092E\u092A\u093F \u092A\u094D\u0930\u0936\u093E\u0928\u094D\u0924\u092D\u0947\u0926\u093E\u0935\u092D\u093E\u0938\u0902 \u092D\u0935\u0924\u0940\u0924\u094D\u092F\u093E\u0939\u2014</p><blockquote><p><strong>\u0936\u0915\u094D\u0924\u093F\u091A\u0915\u094D\u0930\u0938\u0928\u094D\u0927\u093E\u0928\u0947 \u0935\u093F\u0936\u094D\u0935\u0938\u0902\u0939\u093E\u0930\u0903\u0965\u096C\u0965</strong></p></blockquote><p>\u092F\u094B\u093D\u092F\u0902 \u092A\u0930\u092A\u094D\u0930\u0924\u093F\u092D\u094B\u0928\u094D\u092E\u091C\u094D\u091C\u0928\u093E\u0924\u094D\u092E\u094B\u0926\u094D\u092F\u0928\u094D\u0924\u0943\u0924\u093E\u0938\u094D\u0935\u092D\u093E\u0935\u094B \u092D\u0948\u0930\u0935 \u0909\u0915\u094D\u0924\u094B\u093D\u0938\u094D\u092F\u0948\u0935\u093E\u0928\u094D\u0924\u0930\u094D\u0932\u0915\u094D\u0937\u094D\u092F\u092C\u0939\u093F\u0930\u094D\u0926\u0943\u0937\u094D\u091F\u094D\u092F\u093E\u0924\u094D\u092E\u0924\u092F\u093E \u0928\u093F\u0903\u0936\u0947\u0937\u0936\u0915\u094D\u0924\u093F\u091A\u0915\u094D\u0930\u0915\u094D\u0930\u092E\u093E\u0915\u094D\u0930\u092E\u093E\u0915\u094D\u0930\u093E\u092E\u093F\u0923\u094D\u092F\u0924\u093F\u0915\u094D\u0930\u093E\u0928\u094D\u0924\u0915\u094D\u0930\u092E\u093E\u0915\u094D\u0930\u092E\u093E\u0924\u093F\u0930\u093F\u0915\u094D\u0924\u093E\u0930\u093F\u0915\u094D\u0924\u0924\u0926\u0941\u092D\u092F\u093E\u0924\u094D\u092E\u0924\u092F\u093E\u092A\u094D\u092F\u092D\u093F\u0927\u0940\u092F\u092E\u093E\u0928\u093E\u092A\u093F \u0905\u0928\u0947\u0924\u0926\u094D\u0930\u0942\u092A\u093E\u0928\u0941\u0924\u094D\u0924\u0930\u093E \u092A\u0930\u093E \u0938\u094D\u0935\u093E\u0924\u0928\u094D\u0924\u094D\u0930\u094D\u092F\u0936\u0915\u094D\u0924\u093F\u0903 \u0915\u093E\u092A\u094D\u092F\u0938\u094D\u0924\u093F\u0964 \u092F\u092F\u093E \u0938\u094D\u0935\u092D\u093F\u0924\u094D\u0924\u094C \u092E\u0939\u094D\u092F\u0941\u0932\u094D\u0932\u093E\u0938\u093E\u0924\u094D\u092A\u094D\u0930\u092D\u0943\u0924\u093F \u092A\u0930\u092A\u094D\u0930\u092E\u093E\u0924\u0943\u0935\u093F\u0936\u094D\u0930\u093E\u0928\u094D\u0924\u094D\u092F\u0928\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u092E\u0924\u094D\u0938\u0943\u0937\u094D\u091F\u094D\u092F\u093E\u0926\u093F\u0936\u0915\u094D\u0924\u093F\u091A\u0915\u094D\u0930\u0938\u094D\u092B\u093E\u0930\u0923\u093E\u0924\u094D\u092E\u093E \u0915\u094D\u0930\u0940\u0921\u0947\u092F\u092E\u093E\u0926\u0930\u094D\u0936\u093F\u0924\u093E\u0964 \u0924\u0938\u094D\u092F\u0948\u0924\u0926\u093E\u092D\u093E\u0938\u093F\u0924\u0938\u094D\u092F \u0936\u0915\u094D\u0924\u093F\u091A\u0915\u094D\u0930\u0938\u094D\u092F \u0930\u0939\u0938\u094D\u092F\u093E\u092E\u094D\u0928\u093E\u092F\u093E\u092E\u094D\u0928\u093E\u0924\u0928\u0940\u0924\u094D\u092F\u093E \u092F\u0924\u094D\u0938\u0928\u094D\u0927\u093E\u0928\u0902 \u092F\u0925\u094B\u091A\u093F\u0924\u0915\u094D\u0930\u092E\u0935\u093F\u092E\u0930\u094D\u0936\u0928\u0902 \u0924\u0938\u094D\u092E\u093F\u0928\u094D \u0938\u0924\u093F \u0915\u093E\u0932\u093E\u0917\u094D\u0928\u094D\u092F\u093E\u0926\u0947\u0936\u094D\u091A\u0930\u092E\u0915\u0932\u093E\u0928\u094D\u0924\u0938\u094D\u092F \u0935\u093F\u0936\u094D\u0935\u0938\u094D\u092F \u0938\u0902\u0939\u093E\u0930\u094B \u0926\u0947\u0939\u093E\u0924\u094D\u092E\u0924\u092F\u093E \u092C\u093E\u0939\u094D\u092F\u0924\u092F\u093E \u091A\u093E\u0935\u0938\u094D\u0925\u093F\u0924\u0938\u094D\u092F\u093E\u092A\u093F \u0938\u0924\u0903 \u092A\u0930\u0938\u0902\u0935\u093F\u0926\u0917\u094D\u0928\u093F\u0938\u093E\u0926\u094D\u092D\u093E\u0935\u094B \u092D\u0935\u0924\u0940\u0924\u094D\u092F\u0930\u094D\u0925\u0903\u0964 \u0909\u0915\u094D\u0924\u0902 \u091A \u0936\u094D\u0930\u0940\u092D\u0930\u094D\u0917\u0936\u093F\u0916\u093E\u092F\u093E\u092E\u094D</p><blockquote><p>\u092E\u0943\u0924\u094D\u092F\u0941\u0902 \u091A \u0915\u093E\u0932\u0902 \u091A \u0915\u0932\u093E\u0915\u0932\u093E\u092A\u0902 \u0935\u093F\u0915\u093E\u0930\u091C\u093E\u0932\u0902 \u092A\u094D\u0930\u0924\u093F\u092A\u0924\u094D\u0924\u093F\u0938\u093E\u0924\u094D\u092E\u094D\u092F\u092E\u094D|<br> \u0910\u0915\u093E\u0924\u094D\u092E\u094D\u092F\u0928\u093E\u0928\u093E\u0924\u094D\u092E\u094D\u092F\u0935\u093F\u0915\u0932\u094D\u092A\u091C\u093E\u0924\u0902 \u0924\u0926\u093E \u0938 \u0938\u0930\u094D\u0935\u0902 \u0915\u0935\u0932\u0940\u0915\u0930\u094B\u0924\u093F\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0936\u094D\u0930\u0940\u092E\u0926\u094D\u0935\u0940\u0930\u093E\u0935\u0932\u093E\u0935\u092A\u093F</p><blockquote><p>\u092F\u0924\u094D\u0930 \u0938\u0930\u094D\u0935\u0947 \u0932\u092F\u0902 \u092F\u093E\u0928\u094D\u0924\u093F \u0926\u0939\u094D\u092F\u0928\u094D\u0924\u0947 \u0924\u0924\u094D\u0924\u094D\u0935\u0938\u091A\u092F\u093E\u0903|<br> \u0924\u093E\u0902 \u091A\u093F\u0924\u093F\u0902 \u092A\u0936\u094D\u092F \u0915\u093E\u092F\u0938\u094D\u0925\u093E\u0902 \u0915\u093E\u0932\u093E\u0928\u0932\u0938\u092E\u0924\u094D\u0935\u093F\u0937\u092E\u094D\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0936\u094D\u0930\u0940\u092E\u0928\u094D\u092E\u093E\u0932\u093F\u0928\u0940\u0935\u093F\u091C\u092F\u0947\u093D\u092A\u093F</p><blockquote><p>\u0909\u091A\u094D\u091A\u093E\u0930\u0930\u0939\u093F\u0924\u0902 \u0935\u0938\u094D\u0924\u0941 \u091A\u0947\u0924\u0938\u0948\u0935 \u0935\u093F\u091A\u093F\u0928\u094D\u0924\u092F\u0928\u094D|<br> \u092F\u0902 \u0938\u092E\u093E\u0935\u0947\u0936\u092E\u093E\u092A\u094D\u0928\u094B\u0924\u093F \u0936\u093E\u0915\u094D\u0924\u0903 \u0938\u094B\u093D\u0924\u094D\u0930\u093E\u092D\u093F\u0927\u0940\u092F\u0924\u0947\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0941\u0915\u094D\u0924\u094D\u092F\u093E\u0924\u0926\u0947\u0935 \u092D\u0919\u094D\u0917\u094D\u092F\u093E \u0928\u093F\u0930\u0942\u092A\u093F\u0924\u092E\u094D\u0964 \u090F\u0924\u091A\u094D\u091A \u0938\u0926\u094D\u0917\u0941\u0930\u0941\u091A\u0930\u0923\u094B\u092A\u093E\u0938\u0928\u092F\u093E\u092D\u093F\u0935\u094D\u092F\u0915\u094D\u0924\u093F\u092E\u093E\u092F\u093E\u0924\u0940\u0924\u093F \u0928\u093E\u0927\u093F\u0915\u092E\u0941\u0928\u094D\u092E\u0940\u0932\u093F\u0924\u092E\u094D\u0964 \u090F\u0924\u0926\u0947\u0935</p><blockquote><p>\u092F\u0938\u094D\u092F\u094B\u0928\u094D\u092E\u0947\u0937\u0928\u093F\u092E\u0947\u0937\u093E\u092D\u094D\u092F\u093E\u0902...\u0964</p></blockquote><p>\u0907\u0924\u093F</p><blockquote><p>\u092F\u0926\u093E \u0924\u094D\u0935\u0947\u0915\u0924\u094D\u0930 \u0938\u0902\u0930\u0942\u0922\u0903...\u0964</p></blockquote><p>\u0907\u0924\u093F \u091A \u092A\u094D\u0930\u0925\u092E\u091A\u0930\u092E\u0936\u094D\u0932\u094B\u0915\u093E\u092D\u094D\u092F\u093E\u0902 \u0938\u0919\u094D\u0917\u0943\u0939\u0940\u0924\u092E\u094D\u0965\u096C\u0965</p></div><div class="trans"><p>Eva\u1E41 jhagiti parapratibhonme\u1E63\u0101va\u1E63\u1E6Dambhop\u0101yik\u0101\u1E41 bhairavasam\u0101pattimaj\xF1\u0101nabandhapra\u015Bamaikahetu\u1E41 pradar\u015Byaitatpar\u0101mar\u015Baprakar\u1E63\u0101dvyutth\u0101namapi pra\u015B\u0101ntabhed\u0101vabh\u0101sa\u1E41 bhavat\u012Bty\u0101ha\u2014</p><blockquote><h3 id="sakticakrasandhane-visvasamharah-6" tabindex="-1">\u015Aakticakrasandh\u0101ne vi\u015Bvasa\u1E41h\u0101ra\u1E25||6|| <a class="header-anchor" href="#sakticakrasandhane-visvasamharah-6" aria-hidden="true">#</a></h3></blockquote><p>Yo&#39;ya\u1E41 parapratibhonmajjan\u0101tmodyant\u1E5Bt\u0101svabh\u0101vo bhairava ukto&#39;syaiv\u0101ntarlak\u1E63yabahird\u1E5B\u1E63\u1E6Dy\u0101tmatay\u0101 ni\u1E25\u015Be\u1E63a\u015Bakticakrakram\u0101kram\u0101kr\u0101mi\u1E47yatikr\u0101ntakram\u0101kram\u0101tirikt\u0101riktatadubhay\u0101tmatay\u0101pyabhidh\u012Byam\u0101n\u0101pi anetadr\u016Bp\u0101nuttar\u0101 par\u0101 sv\u0101tantrya\u015Bakti\u1E25 k\u0101pyasti| Yay\u0101 svabhittau mahyull\u0101s\u0101tprabh\u1E5Bti parapram\u0101t\u1E5Bvi\u015Br\u0101ntyanta\u1E41 \u015Br\u012Bmats\u1E5B\u1E63\u1E6Dy\u0101di\u015Bakticakrasph\u0101ra\u1E47\u0101tm\u0101 kr\u012B\u1E0Deyam\u0101dar\u015Bit\u0101| Tasyaitad\u0101bh\u0101sitasya \u015Bakticakrasya rahasy\u0101mn\u0101y\u0101mn\u0101tan\u012Bty\u0101 yatsandh\u0101na\u1E41 yathocitakramavimar\u015Bana\u1E41 tasmin sati k\u0101l\u0101gny\u0101de\u015Bcaramakal\u0101ntasya vi\u015Bvasya sa\u1E41h\u0101ro deh\u0101tmatay\u0101 b\u0101hyatay\u0101 c\u0101vasthitasy\u0101pi sata\u1E25 parasa\u1E41vidagnis\u0101dbh\u0101vo bhavat\u012Btyartha\u1E25| Ukta\u1E41 ca \u015Br\u012Bbharga\u015Bikh\u0101y\u0101m</p><blockquote><p>M\u1E5Btyu\u1E41 ca k\u0101la\u1E41 ca kal\u0101kal\u0101pa\u1E41 vik\u0101raj\u0101la\u1E41 pratipattis\u0101tmyam|<br> Aik\u0101tmyan\u0101n\u0101tmyavikalpaj\u0101ta\u1E41 tad\u0101 sa sarva\u1E41 kaval\u012Bkaroti||</p></blockquote><p>iti| \u015Ar\u012Bmadv\u012Br\u0101val\u0101vapi</p><blockquote><p>Yatra sarve laya\u1E41 y\u0101nti dahyante tattvasacay\u0101\u1E25|<br> T\u0101\u1E41 citi\u1E41 pa\u015Bya k\u0101yasth\u0101\u1E41 k\u0101l\u0101nalasamatvi\u1E63am||</p></blockquote><p>iti| \u015Ar\u012Bmanm\u0101lin\u012Bvijaye&#39;pi</p><blockquote><p>Ucc\u0101rarahita\u1E41 vastu cetasaiva vicintayan|<br> Ya\u1E41 sam\u0101ve\u015Bam\u0101pnoti \u015B\u0101kta\u1E25 so&#39;tr\u0101bhidh\u012Byate||</p></blockquote><p>ityukty\u0101itadeva bha\u1E45gy\u0101 nir\u016Bpitam| Etacca sadgurucara\u1E47op\u0101sanay\u0101bhivyaktim\u0101y\u0101t\u012Bti n\u0101dhikamunm\u012Blitam| Etadeva</p><blockquote><p>Yasyonme\u1E63anime\u1E63\u0101bhy\u0101\u1E41...|</p></blockquote><p>iti</p><blockquote><p>Yad\u0101 tvekatra sa\u1E41r\u016B\u1E0Dha\u1E25...|</p></blockquote><p>iti ca prathamacarama\u015Blok\u0101bhy\u0101\u1E41 sa\u1E45g\u1E5Bh\u012Btam||6||</p></div><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam)</em>, \u043F\u043E\u043A\u0430\u0437\u0430\u0432 <em>(pradar\u015Bya)</em>, \u0447\u0442\u043E \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F <em>(eka)</em> \u043F\u0440\u0438\u0447\u0438\u043D\u0430 <em>(hetum)</em> \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u044F <em>(pra\u015Bama)</em> \u043D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u044F <em>(aj\xF1\u0101na)</em> - (\u044D\u0442\u043E) \u043F\u043E\u043B\u043D\u043E\u0435 \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u0435 <em>(sam\u0101pattim)</em> \u0432 Bhairava <em>(bhairava)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 --\u0442.\u0435. \u043F\u043E\u043B\u043D\u043E\u0435 \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u0435-- \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C <em>(up\u0101yik\u0101m)</em> , \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u043D\u044B\u043C _(ava\u1E63\u1E6Dambha) \u043D\u0430 \u043C\u0433\u043D\u043E\u0432\u0435\u043D\u043D\u043E\u043C (\u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0438) <em>(jaghiti)</em> Unme\u1E63a <em>(unme\u1E63a)</em>^&quot;\u2014</p><blockquote><p>\u0427\u0435\u0440\u0435\u0437 \u043E\u0431\u044A\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0435 <em>(sandh\u0101ne)</em> \u0441 \u0441\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0439 \u0433\u0440\u0443\u043F\u043F\u043E\u0439 <em>(cakra)</em> \u0441\u0438\u043B <em>(\u015Bakti)</em>, [\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442] \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u0435 <em>(sa\u1E41h\u0101ra\u1E25)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vi\u015Bva)</em>||6||</p></blockquote><p>\u042D\u0442\u043E\u0442 <em>(ayam)</em> Bhairava <em>(bhairava\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 <em>(ya\u1E25)</em> \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442\u0441\u044F <em>(ukta\u1E25)</em>, \u0438\u043C\u0435\u0435\u0442 \u043F\u0440\u0438\u0440\u043E\u0434\u0443 <em>(sva-bh\u0101va\u1E25)</em> \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u0438\u044F <em>(udyant\u1E5Bt\u0101)</em>, (\u0438\u043B\u0438) \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F <em>(unmajjana-\u0101tm\u0101)</em> \u0432\u044B\u0441\u0448\u0435\u0439 <em>(para)</em> Pratibh\u0101 <em>(pratibh\u0101)</em>. \u0415\u0433\u043E <em>(asya eva)</em> \u0433\u043B\u0430\u0432\u043D\u0430\u044F <em>(anuttar\u0101)</em> \u0438 \u0432\u044B\u0441\u0448\u0430\u044F <em>(par\u0101)</em> \u015Aakti, \u0438\u043B\u0438 \u0421\u0438\u043B\u0430 <em>(\u015Bakti\u1E25)</em> \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0439 \u0421\u0432\u043E\u0431\u043E\u0434\u044B \u0437\u043D\u0430\u0442\u044C \u0438 \u0434\u0435\u043B\u0430\u0442\u044C \u0432\u0441\u0435 <em>(sv\u0101tantrya)</em>, \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(asti)</em> \u0422\u043E\u0439 <em>(k\u0101-api)</em>, \u0447\u044C\u044F \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C <em>(\u0101tmatay\u0101)</em> \u0434\u043E\u043B\u0436\u043D\u0430 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0442\u044C\u0441\u044F <em>(lak\u1E63ya)</em> \u0432\u043D\u0443\u0442\u0440\u0438 <em>(antas)</em> [\u043A\u0430\u043A \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u0438] \u0432\u0438\u0434\u043D\u0430 <em>(d\u1E5B\u1E63\u1E6Dya)</em> \u0432\u043E\u0432\u043D\u0435 <em>(bahis)</em> [\u043A\u0430\u043A \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F. \u041F\u043E\u044D\u0442\u043E\u043C\u0443,] \u041E\u043D\u0430 --\u0442.\u0435. \u015Aakti-- \u043E\u0432\u043B\u0430\u0434\u0435\u0432\u0430\u0435\u0442 <em>(\u0101kr\u0101mi\u1E47\u012B)</em> \u0432\u0441\u0435\u0439 <em>(ni\u1E25\u015Be\u1E63a)</em> \u0433\u0440\u0443\u043F\u043F\u043E\u0439 <em>(cakra)</em> \u0441\u0438\u043B <em>(\u015Bakti)</em>, [\u0438 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043A\u0430\u043A] \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C <em>(krama)</em> [\u0438] \u043D\u0435-\u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C --\u0442.\u0435. \u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0441\u0442\u044C-- <em>(akrama)</em>. [\u0412 \u0441\u0432\u043E\u044E \u043E\u0447\u0435\u0440\u0435\u0434\u044C, \u043A\u043E\u0433\u0434\u0430] \u041E\u043D\u0430 \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u0438\u0442 \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u0438 \u043D\u0435-\u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C <em>(atikr\u0101nta-krama-akrama)</em>, \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0434\u0430\u0436\u0435 \u043A\u0430\u043A <em>(\u0101tmatay\u0101... api)</em> \u0447\u0440\u0435\u0437\u043C\u0435\u0440\u043D\u043E <em>(ati)</em> \u043F\u0443\u0441\u0442\u0430\u044F <em>(rikta)</em> [\u0438] \u043D\u0435-\u043F\u0443\u0441\u0442\u0430\u044F <em>(a-rikta)</em>, (\u0438\u043B\u0438) \u0438 \u0442\u043E, \u0438 \u0434\u0440\u0443\u0433\u043E\u0435 --\u0442.\u0435. \u043E\u0431\u0435 \u0438 \u043E\u0447\u0435\u043D\u044C \u043F\u0443\u0441\u0442\u0430\u044F, \u0438 \u043D\u0435-\u043F\u0443\u0441\u0442\u0430\u044F-- <em>(tad-ubhaya)</em>. [\u041D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435,] \u0445\u043E\u0442\u044F <em>(api)</em> \u041E\u043D\u0430 [\u0442\u0430\u043A] \u043E\u043F\u0438\u0441\u0430\u043D\u0430 <em>(abhidh\u012Byam\u0101n\u0101)</em>, \u041E\u043D\u0430 \u043D\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(an... r\u016Bp\u0101)</em> \u0442\u0430\u043A\u043E\u0432\u043E\u0439 <em>(etad)</em> [\u0442\u043E\u0439 \u0438\u043B\u0438 \u0434\u0440\u0443\u0433\u043E\u0439]|</p><p>\u042D\u0442\u0430 <em>(iyam)</em> \u0418\u0433\u0440\u0430 <em>(kr\u012B\u1E0D\u0101)</em>, \u0447\u044C\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 <em>(\u0101tm\u0101)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0441\u0432\u0435\u0440\u043A\u0430\u044E\u0449\u0430\u044F \u0432\u0438\u0431\u0440\u0430\u0446\u0438\u044F <em>(sph\u0101ra\u1E47a)</em> \u0433\u0440\u0443\u043F\u043F\u044B <em>(cakra)</em> \u0441\u0438\u043B <em>(\u015Bakti)</em> [\u0432 \u0444\u043E\u0440\u043C\u0435] \u043F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u043E\u0439 <em>(\u015Br\u012Bmat)</em> \u044D\u043C\u0430\u043D\u0430\u0446\u0438\u0438 <em>(s\u1E5B\u1E63\u1E6Di)</em> \u0438 \u0442.\u043F. <em>(\u0101di)</em>, \u043D\u0430\u0447\u0438\u043D\u0430\u044F <em>(prabh\u1E5Bti)</em> \u0441 \u043C\u0430\u043D\u0438\u0444\u0435\u0441\u0442\u0430\u0446\u0438\u0438 <em>(ull\u0101s\u0101t)</em> \u0437\u0435\u043C\u043B\u0438 --\u0442\u0430\u0442\u0442\u0432\u044B, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438 36-- <em>(mah\u012B)</em> [\u0438] \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F <em>(antam)</em> \u0432 \u0432\u0435\u0447\u043D\u043E\u043C \u043F\u043E\u043A\u043E\u0435 <em>(vi\u015Br\u0101nti)</em> \u0432\u044B\u0441\u0448\u0435\u0433\u043E <em>(para)</em> \u0412\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0435\u0433\u043E <em>(pram\u0101t\u1E5B)</em> --\u015Aiva - \u0442\u0430\u0442\u0442\u0432\u0435, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438 1--, \u043F\u043E\u043A\u0430\u0437\u0430\u043D\u0430 <em>(\u0101dar\u015Bit\u0101)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u044D\u0442\u043E\u0439 [\u0432\u044B\u0441\u0448\u0435\u0439 \u0421\u0438\u043B\u044B \u0413\u043E\u0441\u043F\u043E\u0434\u0430] <em>(yay\u0101)</em> \u043D\u0430 \u0415\u0435--\u015Aakti, \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u0439 \u0421\u0438\u043B\u044B-- \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C <em>(sva)</em> \u043F\u043E\u043B\u043E\u0442\u043D\u0435 --\u0442.\u0435. \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u0438\u0438, \u0438\u043B\u0438 \u0444\u043E\u043D\u0435-- <em>(bhittau)</em>|</p><p>Sandh\u0101na, \u0438\u043B\u0438 \u0441\u043E\u044E\u0437 --\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u044B\u0439 \u0432 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435-- <em>(yad sandh\u0101nam)</em> \u044D\u0442\u043E\u0439 <em>(tasya)</em> \u0433\u0440\u0443\u043F\u043F\u044B <em>(cakrasya)</em> \u0441\u0438\u043B <em>(\u015Bakti)</em>, \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u044B\u0445 <em>(abh\u0101sitasya)</em> \u044D\u0442\u043E\u0439 [\u0432\u044B\u0441\u0448\u0435\u0439 \u0421\u0438\u043B\u043E\u0439] <em>(etad)</em>, (\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F) \u0430\u043A\u0442\u043E\u043C \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(vimar\u015Bana\u1E41)</em> \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u043C <em>(yath\u0101-ucita)</em> \u0441\u043F\u043E\u0441\u043E\u0431\u043E\u043C <em>(krama)</em>, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043D\u0430\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u044F\u043C <em>(n\u012Bty\u0101)</em>, \u043E\u043F\u0438\u0441\u0430\u043D\u043D\u044B\u043C <em>(\u0101mn\u0101ta)</em> \u0432 \u0421\u0435\u043A\u0440\u0435\u0442\u043D\u043E\u0439 <em>(rahasya)</em> \u0422\u0440\u0430\u0434\u0438\u0446\u0438\u0438 <em>(\u0101mn\u0101ya)</em>. \u041A\u043E\u0433\u0434\u0430 \u044D\u0442\u043E \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 --\u0442.\u0435. \u043A\u043E\u0433\u0434\u0430 \u0441\u043B\u0443\u0447\u0430\u0435\u0442\u0441\u044F sandh\u0101na-- <em>(tasmin sati)</em>, [\u0442\u043E\u0433\u0434\u0430 \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E] \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u0435 <em>(sa\u1E41h\u0101ra\u1E25)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vi\u015Bvasya)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442\u0441\u044F <em>(\u0101de\u1E25)</em> \u0432 K\u0101l\u0101gni <em>(k\u0101l\u0101gni)</em> [\u0438] \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F <em>(antasya)</em> \u0432 \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u0439 <em>(carama)</em> Kal\u0101 <em>(kal\u0101)</em>^. [\u0411\u043E\u043B\u0435\u0435 \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u043E,] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u0438\u043B\u0438 \u0443\u0441\u043B\u043E\u0432\u0438\u0435 <em>(bh\u0101va\u1E25)</em> \u0432\u043D\u0435\u0448\u043D\u0435\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F <em>(sata\u1E25)</em>, \u0434\u0430\u0436\u0435 \u0435\u0441\u043B\u0438 <em>(api)</em> \u043E\u043D\u043E \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u0442\u0441\u044F <em>(avasthitasya)</em> \u0432 \u0444\u043E\u0440\u043C\u0435 <em>(\u0101tmatay\u0101)</em> \u0442\u0435\u043B\u0430 <em>(deha)</em> \u0438 <em>(ca)</em> \u0432\u043D\u0435\u0448\u043D\u0435\u0433\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F <em>(b\u0101hyatay\u0101)</em>, \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u043D\u044B\u043C <em>(s\u0101t... bhavati)</em> \u0432 \u043E\u0433\u043D\u0435 <em>(agni)</em> \u0432\u044B\u0441\u0448\u0435\u0433\u043E <em>(para)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(sa\u1E41vid)</em>. \u0412 \u044D\u0442\u043E\u043C \u0441\u043C\u044B\u0441\u043B <em>(iti artha\u1E25)</em>|</p><p>\u042D\u0442\u043E \u0442\u0430\u043A\u0436\u0435 \u0431\u044B\u043B\u043E \u043F\u0440\u043E\u0432\u043E\u0437\u0433\u043B\u0430\u0448\u0435\u043D\u043E <em>(uktam ca)</em> \u0432 \u043F\u043E\u0447\u0442\u0435\u043D\u043D\u043E\u0439 <em>(\u015Br\u012B)</em> Bharga\u015Bikh\u0101 <em>(bharga\u015Bikh\u0101y\u0101m)</em>:</p><blockquote><p>&quot;\u0417\u0430\u0442\u0435\u043C <em>(tad\u0101)</em>, [\u043A\u043E\u0433\u0434\u0430 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0442\u0430\u043A\u043E\u0435 \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u0435 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439,] \u043E\u043D --\u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u044B\u0439 Yog\u012B-- <em>(sa\u1E25)</em> \u043F\u043E\u0433\u043B\u043E\u0449\u0430\u0435\u0442 <em>(kaval\u012B-karoti)</em> \u0432\u0441\u0435 <em>(sarvam)</em> --\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0435\u0434\u0438\u043D\u044B\u043C \u0441\u043E \u0432\u0441\u0435\u043C--, [\u0431\u0443\u0434\u044C \u0442\u043E] \u0441\u043C\u0435\u0440\u0442\u044C <em>(m\u1E5Btyum)</em> \u0438 <em>(ca... ca)</em> \u0432\u0440\u0435\u043C\u044F --K\u0101la \u0442\u0430\u043A\u0436\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u043E\u043C, \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u044E\u0449\u0438\u043C \u0441\u043C\u0435\u0440\u0442\u044C\u044E-- <em>(k\u0101lam)</em>, \u0441\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u044C <em>(kal\u0101pam)</em> \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439 <em>(kal\u0101)</em>, \u0446\u0435\u043F\u044C <em>(j\u0101lam)</em> \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u0439 <em>(vik\u0101ra)</em>, \u0438\u0434\u0435\u043D\u0442\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F <em>(s\u0101tmyam)</em> \u0441\u043E \u0437\u043D\u0430\u043D\u0438\u0435\u043C [\u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432] <em>(pratipatti)</em>, \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E <em>(j\u0101tam)</em> \u043C\u044B\u0441\u043B\u0435\u0439 <em>(vikalpa)</em> \u043E \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435 [\u0441 \u0412\u044B\u0441\u0448\u0438\u043C \u042F] <em>(aika-\u0101tmya)</em> [\u0438\u043B\u0438] \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 <em>(n\u0101n\u0101-\u0101tmya... iti)</em>&quot;||</p></blockquote><p>\u0414\u0430\u0436\u0435 <em>(api)</em> \u0432 \u043F\u043E\u0447\u0442\u0435\u043D\u043D\u043E\u0439 <em>(\u015Br\u012Bmat)</em> V\u012Br\u0101val\u012B <em>(v\u012Br\u0101valau)</em> [\u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u0435\u0442\u0441\u044F, \u0447\u0442\u043E]:</p><blockquote><p>&quot;\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u0439 <em>(pa\u015Bya)</em> \u044D\u0442\u043E <em>(t\u0101m)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(citim)</em>, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0435\u0435 <em>(sth\u0101m)</em> \u0432 \u0442\u0435\u043B\u0435 <em>(k\u0101ya)</em>, [\u0438] \u0447\u044C\u0435 \u0432\u0435\u043B\u0438\u043A\u043E\u043B\u0435\u043F\u0438\u0435 <em>(tvi\u1E63am)</em> \u043F\u043E\u0434\u043E\u0431\u043D\u043E <em>(sama)</em> K\u0101l\u0101gnirudra <em>(k\u0101la-anala)</em>^. [\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u0439 \u044D\u0442\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435], \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C <em>(yatra)</em> \u0432\u0441\u0435 <em>(sarve)</em> \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u043E <em>(layam y\u0101nti)</em>, [\u0438] \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E <em>(sacay\u0101\u1E25)</em> \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u043E\u0432, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0439 <em>(tattva)</em> \u0441\u043E\u0436\u0436\u0435\u043D\u043E <em>(dahyante... iti)</em>||</p></blockquote><p>\u0412 \u043E\u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u043C \u0432\u0435\u043A\u0430\u043C\u0438 <em>(\u015Br\u012Bmat)</em> M\u0101lin\u012Bvijayatantra <em>(m\u0101lin\u012Bvijaye)</em> \u0442\u0430\u043A\u0436\u0435 [\u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F] <em>(api)</em>:</p><blockquote><p>&quot;\u0422\u043E\u0442, \u043A\u0442\u043E \u0440\u0430\u0437\u043C\u044B\u0448\u043B\u044F\u0435\u0442 <em>(vicintayan)</em> \u0441\u0432\u043E\u0438\u043C \u0443\u043C\u043E\u043C <em>(cetas\u0101 eva)</em> \u043D\u0430\u0434 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E <em>(vastu)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u0437\u0430 \u043F\u0440\u0435\u0434\u0435\u043B\u0430\u043C\u0438 _(rahitam) \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0448\u0435\u043D\u0438\u044F <em>(ucc\u0101ra)</em>, \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 _(\u0101pnoti) \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u044F [\u0432 \u0412\u044B\u0441\u0448\u0435\u043C \u042F] <em>(yam sam\u0101ve\u015Bam)</em>. \u0417\u0434\u0435\u0441\u044C <em>(atra)</em>, \u044D\u0442\u043E [\u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u0435] <em>(sa\u1E25)</em> \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u0447\u0438\u0442\u0430\u0442\u044C <em>(abhidh\u012Byate)</em>, \u043A\u0430\u043A \u015B\u0101kta --\u0442.\u0435. \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0442\u043E\u0433\u043E \u0447\u0435\u0440\u0435\u0437 \u015A\u0101ktop\u0101ya-- <em>(\u015B\u0101kta\u1E25... iti)</em>&quot;||<br> [\u0421\u043C. M\u0101lin\u012Bvijayatantra II, 22]</p></blockquote><p>\u0421 \u043F\u043E\u043C\u043E\u0449\u044C\u044E \u0442\u0430\u043A\u043E\u0433\u043E \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u044F <em>(ukty\u0101)</em> \u044D\u0442\u043E \u0441\u0430\u043C\u043E\u0435 [\u015Bakticakrasandh\u0101na, \u0438\u043B\u0438 \u0441\u043E\u044E\u0437 \u0441 \u0441\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0439 \u0433\u0440\u0443\u043F\u043F\u043E\u0439 \u0441\u0438\u043B] <em>(etad eva)</em> \u0431\u044B\u043B\u043E \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0435\u043D\u043E <em>(nir\u016Bpitam)</em> \u043A\u043E\u0441\u0432\u0435\u043D\u043D\u043E <em>(bha\u1E45gy\u0101)</em> [\u0432 M\u0101lin\u012Bvijayatantra]|</p><p>\u0418 <em>(ca)</em> \u044D\u0442\u043E <em>(etad)</em> \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 <em>(abhivyaktim \u0101y\u0101ti)</em> \u0447\u0435\u0440\u0435\u0437 \u0441\u043B\u0443\u0436\u0435\u043D\u0438\u0435 <em>(up\u0101sanay\u0101)</em> \u0441\u0442\u043E\u043F\u0430\u043C <em>(cara\u1E47a)</em> \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0433\u043E <em>(sat)</em> \u0413\u0443\u0440\u0443 <em>(guru)</em>. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(iti)</em>, \u0431\u043E\u043B\u044C\u0448\u0435 \u043D\u0438\u0447\u0435\u0433\u043E <em>(na adhikam)</em> \u043D\u0435 \u0431\u044B\u043B\u043E \u044F\u0432\u043B\u0435\u043D\u043E <em>(unm\u012Blitam)</em>|</p><p>\u0422\u043E \u0436\u0435 \u0441\u0430\u043C\u043E\u0435 <em>(etad eva)</em> \u0431\u044B\u043B\u043E \u043E\u0431\u043E\u0431\u0449\u0435\u043D\u043E <em>(sa\u1E45g\u1E5Bh\u012Btam)</em> \u0432 \u0434\u0432\u0443\u0445 \u0448\u043B\u043E\u043A\u0430\u0445 <em>(\u015Blok\u0101bhy\u0101\u1E41)</em> [Spandak\u0101rik\u0101-s], \u0442.\u0435. \u0432 \u043F\u0435\u0440\u0432\u043E\u0439 [\u0448\u043B\u043E\u043A\u0435 \u0420\u0430\u0437\u0434\u0435\u043B\u0430 I] <em>(prathama)</em> [\u0438] \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u0439 [\u0432 \u0420\u0430\u0437\u0434\u0435\u043B\u0435 III] <em>(carama)</em>:</p><blockquote><p>&quot;... \u0447\u044C\u0438\u043C <em>(yasya)</em> \u043E\u0442\u043A\u0440\u044B\u0442\u0438\u0435\u043C [\u0438] \u0437\u0430\u043A\u0440\u044B\u0442\u0438\u0435\u043C [\u0415\u0433\u043E] \u0433\u043B\u0430\u0437 <em>(unme\u1E63a-nime\u1E63\u0101bhy\u0101m... iti)</em>...&quot;||<br> [\u0421\u043C. Spandak\u0101rik\u0101-s I, 1]</p></blockquote><blockquote><p>&quot;\u041D\u043E <em>(tu)</em> \u043A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0435 \u0443\u043A\u043E\u0440\u0435\u043D\u0435\u043D\u0438\u0435 <em>(sa\u1E41r\u016B\u1E0Dha\u1E25)</em> \u0432 \u043E\u0434\u043D\u043E\u043C \u043C\u0435\u0441\u0442\u0435 --\u0442.\u0435. \u0432 \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u0435 Spanda-- <em>(ekatra... iti ca)</em>...&quot;||<br> [\u0421\u043C. Spandak\u0101rik\u0101-s III, 19]</p></blockquote><p>||6||</p><hr><ol><li><p>\u042D\u0442\u043E\u0442 \u0442\u0435\u0440\u043C\u0438\u043D \u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442: &quot;\u0430\u043A\u0442 \u043E\u0442\u043A\u0440\u044B\u0442\u0438\u044F \u0433\u043B\u0430\u0437, \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F, \u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u0438\u044F \u0432\u0438\u0434\u0438\u043C\u044B\u043C \u0438 \u0442.\u0434.&quot;. \u0417\u0434\u0435\u0441\u044C \u044D\u0442\u043E \u0434\u043E\u043B\u0436\u043D\u043E \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C\u0441\u044F \u043A\u0430\u043A &quot;\u0432\u043E\u0437\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u0435&quot;.</p></li><li><p>Vyutth\u0101na - \u044D\u0442\u043E \u043B\u044E\u0431\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u043A\u0440\u043E\u043C\u0435 sam\u0101dhi (\u0432 \u0434\u0430\u043D\u043D\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435, &quot;\u0438\u0434\u0435\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u044F \u0432 Bhairava&quot;). \u041A\u043E\u0440\u043E\u0447\u0435 \u0433\u043E\u0432\u043E\u0440\u044F, \u044D\u0442\u043E \u043E\u0431\u044B\u0447\u043D\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u043F\u043E\u0434\u0430\u0432\u043B\u044F\u044E\u0449\u0435\u0435 \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u043B\u044E\u0434\u0435\u0439.</p></li><li><p>K\u0101l\u0101gni \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u0430\u043C\u044B\u043C \u043D\u0438\u0437\u043A\u0438\u043C \u0438\u0437 bhuvana, \u0438\u043B\u0438 \u043C\u0438\u0440\u043E\u0432, \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u044F\u044F Kal\u0101 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430 \u043A\u0430\u043A \u015A\u0101ntyat\u012Bta.</p></li><li><p>\u041E\u043D \u0442\u0430\u043A\u0436\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u0435\u043D \u043A\u0430\u043A K\u0101l\u0101gnibhuvane\u015Ba (\u0432\u043B\u0430\u0434\u044B\u043A\u0430 \u043C\u0438\u0440\u0430, \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u044B\u0439 K\u0101l\u0101gni). \u041A\u043E\u0440\u043E\u0447\u0435 \u0433\u043E\u0432\u043E\u0440\u044F, \u043E\u043D \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u043E\u043C, \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u0438\u0440\u0443\u044E\u0449\u0438\u043C \u0442\u0430\u043A\u043E\u0439 \u043C\u0438\u0440, \u0438\u043B\u0438 bhuvana. \u041D\u0430\u0437\u0432\u0430\u043D\u0438\u0435 \u044D\u0442\u043E\u0433\u043E bhuvana \u043C\u043E\u0436\u043D\u043E \u043F\u0435\u0440\u0435\u0432\u0435\u0441\u0442\u0438 \u043A\u0430\u043A &quot;\u043E\u0433\u043E\u043D\u044C (\u043A\u043E\u043D\u0446\u0430) \u0432\u0440\u0435\u043C\u0435\u043D\u0438&quot;. \u042D\u0442\u043E \u0441\u0430\u043C\u044B\u0439 \u043D\u0438\u0437\u043A\u0438\u0439 \u0438\u0437 \u043C\u0438\u0440\u043E\u0432, \u043A\u0430\u043A \u044F \u0443\u0436\u0435 \u0441\u043A\u0430\u0437\u0430\u043B \u0432 \u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0435\u043C \u043F\u0440\u0438\u043C\u0435\u0447\u0430\u043D\u0438\u0438.</p></li></ol></div>',1),p=[r];function s(n,k,h,o,y,v){return m(),e("div",null,p)}var u=a(i,[["render",s]]);export{c as __pageData,u as default};
